mapper.select:
SELECT RNUM, 0 AS CHK, ItemID, Identifier, ItemTypeCode, Path, Site, SiteCode, DocLevCode, DocLev, AreaCode, Area, DocFieldCode, DocField, DocTypeCode, DocType, MfProCode, MfProcess, DetailCode , DetailMfProc, NctCode, NctVal, KeyWord, Model, Line, ProcCodeLine, ItemName, ClassCode, OwnerTeamName, Name, LastUpdated, CreationTime, Version, CSVersion, ProcessInfo, SiteCode, ItemTypeName, Status, StatusName, CSStatus, CSStatusName, PItemID, AuthorID FROM ( SELECT Row_Number() OVER(ORDER BY TI.CreationTime DESC) AS RNUM, TI.ItemID, TI.Identifier AS Identifier, TI.ItemTypeCode AS ItemTypeCode, ISNULL(TIPT.Path, '') AS Path, ISNULL(TIA.PlainText, '') AS ItemName, AggData.Site AS Site, AggData.SiteCode AS SiteCode, ISNULL(TIA3.LovCode,'') AS DocLevCode, ISNULL(LOV2.Value,'') AS DocLev, ISNULL(TIA4.LovCode,'') AS AreaCode, ISNULL(LOV3.Value,'') AS Area, ISNULL(TIA5.LovCode,'') AS DocFieldCode, ISNULL(LOV4.Value,'') AS DocField, ISNULL(TIA6.LovCode,'') AS DocTypeCode, ISNULL(LOV5.Value,'') AS DocType, ISNULL(TIA7.LovCode,'') AS MfProCode, ISNULL(LOV6.Value,'') AS MfProcess, ISNULL(TIA8.LovCode,'') AS DetailCode, ISNULL(LOV7.Value,'') AS DetailMfProc, ISNULL(TIA9.LovCode, '') AS NctCode, ISNULL(LOV8.Value, '') AS NctVal, ISNULL(TIA10.PlainText,'')AS KeyWord, ISNULL(TIA11.PlainText,'')AS Model, ISNULL(TIA12.PlainText,'')AS Line, ISNULL(TIA13.PlainText,'') AS ProcCodeLine, TI.ClassCode, TOT.Name AS OwnerTeamName, CASE WHEN #{LanguageID} In (1042,2052,1041) THEN TM.Name ELSE ISNULL(TM.NameEN,TM.Name) END AS Name, TI.Version, ISNULL(TIAF.PlainText,'') AS ProcessInfo, TI.Status, TSD.Name AS StatusName, TCS.Status as CSStatus, TCD.Name AS CSStatusName, TID.Name AS ItemTypeName, CONVERT(nvarchar(10), TCSM.ApproveDate, 120) AS LastUpdated, ISNULL(CONVERT(nvarchar(10), TCSN.ApproveDate, 120),CONVERT(nvarchar(10), TI.CreationTime,120)) AS CreationTime, TCS.Version AS CSVersion,
ISNULL(ST.FromItemID, '') AS PItemID,
TI.AuthorID FROM XBOLTADM.TB_ITEM TI INNER JOIN ( SELECT DIM.ItemID, STUFF(( SELECT ', ' + DTXT2.Name FROM XBOLTADM.TB_ITEM_DIM DIM2 INNER JOIN XBOLTADM.TB_DIM_VALUE TDV2 ON DIM2.DimValueID = TDV2.DimValueID INNER JOIN XBOLTADM.TB_DIM_VALUE_TXT DTXT2 ON DTXT2.DimValueID = DIM2.DimValueID AND DTXT2.LanguageID = #{languageID} WHERE DIM2.ItemID = DIM.ItemID ORDER BY TDV2.SortNum FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS Site, STUFF(( SELECT ', ' + TDV2.DimValueID FROM XBOLTADM.TB_ITEM_DIM DIM2 INNER JOIN XBOLTADM.TB_DIM_VALUE TDV2 ON DIM2.DimValueID = TDV2.DimValueID WHERE DIM2.ItemID = DIM.ItemID ORDER BY TDV2.SortNum FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS SiteCode FROM XBOLTADM.TB_ITEM_DIM DIM GROUP BY DIM.ItemID ) AggData ON AggData.ItemID = TI.ItemID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TI.Status = TSD.TypeCode AND TSD.LanguageID = #{LanguageID} AND TSD.Category = 'ITMSTS' LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TID ON TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT ON TI.CompanyID = TT.TeamID AND TT.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAF ON TI.ItemID = TIAF.ItemID AND TIAF.AttrTypeCode = 'AT00003' AND TIAF.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 ON TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'ZAT01020' AND TIA3.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 ON TI.ItemID = TIA4.ItemID AND TIA4.AttrTypeCode = 'ZAT01030' AND TIA4.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 ON TI.ItemID = TIA5.ItemID AND TIA5.AttrTypeCode = 'ZAT01040' AND TIA5.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA6 ON TI.ItemID = TIA6.ItemID AND TIA6.AttrTypeCode = 'ZAT01060' AND TIA6.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA7 ON TI.ItemID = TIA7.ItemID AND TIA7.AttrTypeCode = 'ZAT01050' AND TIA7.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 ON TI.ItemID = TIA8.ItemID AND TIA8.AttrTypeCode = 'ZAT01051' AND TIA8.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA9 ON TI.ItemID = TIA9.ItemID AND TIA9.AttrTypeCode = 'AT00040' AND TIA9.LanguageID = '1042' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA10 ON TI.ItemID = TIA10.ItemID AND TIA10.AttrTypeCode = 'AT01007' AND TIA10.LanguageID = #{LanguageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA11 ON TI.ItemID = TIA11.ItemID AND TIA11.AttrTypeCode = 'ZAT09005'AND TIA11.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA12 ON TI.ItemID = TIA12.ItemID AND TIA12.AttrTypeCode = 'ZAT09006'AND TIA12.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA13 ON TI.ItemID = TIA13.ItemID AND TIA13.AttrTypeCode = 'ZAT09007' AND TIA13.LanguageID = #{LanguageID}
LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV2 ON LOV2.LovCode = TIA3.LovCode AND LOV2.AttrTypeCode = 'ZAT01020' AND LOV2.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV3 ON LOV3.LovCode = TIA4.LovCode AND LOV3.AttrTypeCode = 'ZAT01030' AND LOV3.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV4 ON LOV4.LovCode = TIA5.LovCode AND LOV4.AttrTypeCode = 'ZAT01040' AND LOV4.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV5 ON LOV5.LovCode = TIA6.LovCode AND LOV5.AttrTypeCode = 'ZAT01060' AND LOV5.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV6 ON LOV6.LovCode = TIA7.LovCode AND LOV6.AttrTypeCode = 'ZAT01050' AND LOV6.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV7 ON LOV7.LovCode = TIA8.LovCode AND LOV7.AttrTypeCode = 'ZAT01051' AND LOV7.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV8 ON LOV8.LovCode = TIA9.LovCode AND LOV8.AttrTypeCode = 'AT00040' AND LOV8.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TI.CurChangeSet = TCS.ChangeSetID
LEFT OUTER JOIN XBOLTADM.TB_ITEM ST ON TI.ItemID = ST.ToItemID AND ST.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TW_ITEM_PATH_TXT TIPT ON TIPT.ItemID = TI.ItemID AND TIPT.LanguageID = #{LanguageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TCD ON TCS.Status = TCD.TypeCode AND TCD.LanguageID = #{LanguageID} AND TCD.Category = 'CNGSTS' LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSN ON TI.ItemID = TCSN.ItemID AND TCSN.ChangeType = 'NEW' LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSM ON TI.ItemID = TCSM.ItemID AND TCSM.ChangeType = 'MOD' AND TI.ReleaseNo = TCSM.ChangeSetID
WHERE (TI.Deleted != 1 ) AND TI.ClassCode = #{ClassCode}
AND TI.ItemID IN (${childItems})
AND ( TI.ItemID IN( Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in ('SKO1') )
AND TI.ItemID IN( Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in (${siteCode}) )
)
AND TI.ItemID IN( Select ItemID from XBOLTADM.TB_ITEM_DIM Where DimTypeID = '100001' AND DimValueID in (${siteCode}) )
And TCS.Status = #{csStatus}
AND ISNULL(TCSN.ApproveDate, TI.CreationTime) BETWEEN #{SC_STR_DT1} AND #{SC_END_DT1}
AND TCSM.ApproveDate BETWEEN #{SC_STR_DT2} AND #{SC_END_DT2}
) A WHERE 1 = 1
And (Identifier like N'%'+#{searchValue}+'%' OR itemName like N'%'+#{searchValue}+'%')
AND ( itemName like N'%'+#{totalInfo}+'%' OR Keyword like N'%'+#{totalInfo}+'%' OR ProcessInfo like N'%'+#{totalInfo}+'%' )
And Identifier like N'%'+#{identifier}+'%'
And itemName like N'%'+#{itemName}+'%'
And Status = #{status}
And Status = #{ownerTeamID}
And Name like N'%'+#{authorName}+'%'
And AreaCode = #{ZAT01030}
And DocTypeCode = #{ZAT01060}
And DocFieldCode = #{ZAT01040}
And DocLevCode = #{ZAT01020}
And MfProCode = #{ZAT01050}
And DetailCode IN (
#{item}
)
And Model like N'%'+#{ZAT09005}+'%'
And Line like N'%'+#{ZAT09006}+'%'
And ProcCodeLine like N'%'+#{ZAT09007}+'%'
AND NctCode = #{AT00040}
And ProcessInfo like N'%'+#{processInfo}+'%'
And Keyword like N'%'+#{keyWord}+'%'
And OwnerTeamName like N'%'+#{ownerTeamName}+'%'

		WITH AggData AS (
	    SELECT
	        ItemID,
	        STUFF((
	            SELECT ', ' + DTXT2.Name
	            FROM XBOLTADM.TB_ITEM_DIM DIM2
	            INNER JOIN XBOLTADM.TB_DIM_VALUE TDV2 ON DIM2.DimValueID = TDV2.DimValueID
	            INNER JOIN XBOLTADM.TB_DIM_VALUE_TXT DTXT2 ON DTXT2.DimValueID = DIM2.DimValueID AND DTXT2.LanguageID = #{LanguageID}
	            WHERE DIM2.ItemID = DIM.ItemID AND DIM2.DimTypeID = '100001'
	            ORDER BY TDV2.SortNum
	            FOR XML PATH(''), TYPE
	        ).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS Site,
	        STUFF((
	            SELECT ', ' + TDV2.DimValueID
	            FROM XBOLTADM.TB_ITEM_DIM DIM2
	            INNER JOIN XBOLTADM.TB_DIM_VALUE TDV2 ON DIM2.DimValueID = TDV2.DimValueID
	            WHERE DIM2.ItemID = DIM.ItemID AND DIM2.DimTypeID = '100001'
	            ORDER BY TDV2.SortNum
	            FOR XML PATH(''), TYPE
	        ).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS SiteCode
	    FROM XBOLTADM.TB_ITEM_DIM DIM
	    WHERE DIM.ItemID IN ( 
		 
		 	
		 		${childItems}
		 	
		 	
		 		''
		 	
		 
		 )
	    	GROUP BY DIM.ItemID
		)

		    SELECT 
		        Row_Number() OVER(ORDER BY TI.CreationTime DESC) AS RNUM,
		        TI.ItemID,
				TI.Identifier AS Identifier,
		        TI.ItemTypeCode AS ItemTypeCode,
		        ISNULL(TIPT.Path, '') AS Path,
		        ISNULL(TIA.PlainText, '') AS ItemName,
				AggData.Site AS Site,
				AggData.SiteCode AS SiteCode,
				ISNULL(TIA3.LovCode,'') AS DocLevCode, 
		        ISNULL(LOV2.Value,'') AS DocLev, 
		        ISNULL(TIA4.LovCode,'') AS AreaCode, 
		        ISNULL(LOV3.Value,'') AS Area, 
		        ISNULL(TIA5.LovCode,'') AS DocFieldCode, 
		        ISNULL(LOV4.Value,'') AS DocField, 
		        ISNULL(TIA6.LovCode,'') AS DocTypeCode, 
		        ISNULL(LOV5.Value,'') AS DocType, 
		        ISNULL(TIA7.LovCode,'') AS MfProCode, 
		        ISNULL(LOV6.Value,'') AS MfProcess, 
		        ISNULL(TIA8.LovCode,'') AS DetailCode, 
		        ISNULL(LOV7.Value,'') AS DetailMfProc, 
		        ISNULL(TIA9.LovCode, '') AS NctCode, 
		        ISNULL(LOV8.Value, '') AS NctVal, 
                ISNULL(TIA10.PlainText,'')AS KeyWord,
                ISNULL(TIA11.PlainText,'')AS Model,
				ISNULL(TIA12.PlainText,'')AS Line,
				ISNULL(TIA13.PlainText,'') AS ProcCodeLine,
		        TI.ClassCode,
		        TOT.Name AS OwnerTeamName,
		        CASE WHEN #{LanguageID} In (1042,2052,1041) THEN TM.Name ELSE ISNULL(TM.NameEN,TM.Name) END AS Name,
		        TI.Version,
		        ISNULL(TIAF.PlainText,'') AS ProcessInfo,
		        TI.Status,
		        TSD.Name AS StatusName,
				TCS.Status as CSStatus,
				TCD.Name AS CSStatusName,
		        TID.Name AS ItemTypeName,
		        CONVERT(nvarchar(10), TCSM.ApproveDate, 120) AS LastUpdated,
		        ISNULL(CONVERT(nvarchar(10), TCSN.ApproveDate, 120),CONVERT(nvarchar(10), TI.CreationTime,120)) AS CreationTime,
		        TCS.Version AS CSVersion,		 
		        ISNULL(ST.FromItemID, '') AS PItemID,
		        TI.AuthorID
		    FROM XBOLTADM.TB_ITEM TI
    		INNER JOIN AggData ON AggData.ItemID = TI.ItemID
		    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TI.Status = TSD.TypeCode AND TSD.LanguageID = #{LanguageID} AND TSD.Category = 'ITMSTS'
		    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TID ON TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{LanguageID}

		    LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{LanguageID}
		    LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID
		    LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{LanguageID}
		    LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAF ON TI.ItemID = TIAF.ItemID AND TIAF.AttrTypeCode = 'AT00003' AND TIAF.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 ON TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'ZAT01020' AND TIA3.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 ON TI.ItemID = TIA4.ItemID AND TIA4.AttrTypeCode = 'ZAT01030' AND TIA4.LanguageID = #{LanguageID}
		    LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 ON TI.ItemID = TIA5.ItemID AND TIA5.AttrTypeCode = 'ZAT01040' AND TIA5.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA6 ON TI.ItemID = TIA6.ItemID AND TIA6.AttrTypeCode = 'ZAT01060' AND TIA6.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA7 ON TI.ItemID = TIA7.ItemID AND TIA7.AttrTypeCode = 'ZAT01050' AND TIA7.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 ON TI.ItemID = TIA8.ItemID AND TIA8.AttrTypeCode = 'ZAT01051' AND TIA8.LanguageID = #{LanguageID}
		    LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA9 ON TI.ItemID = TIA9.ItemID AND TIA9.AttrTypeCode = 'AT00040' AND TIA9.LanguageID = #{LanguageID}			
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA10 ON TI.ItemID = TIA10.ItemID AND TIA10.AttrTypeCode = 'AT01007' AND TIA10.LanguageID = #{LanguageID}		
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA11 ON TI.ItemID = TIA11.ItemID AND TIA11.AttrTypeCode = 'ZAT09005'AND TIA11.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA12 ON TI.ItemID = TIA12.ItemID AND TIA12.AttrTypeCode = 'ZAT09006'AND TIA12.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA13 ON TI.ItemID = TIA13.ItemID AND TIA13.AttrTypeCode = 'ZAT09007' AND TIA13.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV2 ON LOV2.LovCode = TIA3.LovCode　AND LOV2.AttrTypeCode  = 'ZAT01020' AND LOV2.LanguageID =  #{LanguageID}
   		 	LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV3 ON LOV3.LovCode = TIA4.LovCode　AND LOV3.AttrTypeCode  = 'ZAT01030' AND LOV3.LanguageID =  #{LanguageID}
    		LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV4 ON LOV4.LovCode = TIA5.LovCode　AND LOV4.AttrTypeCode  = 'ZAT01040' AND LOV4.LanguageID =  #{LanguageID}
    		LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV5 ON LOV5.LovCode = TIA6.LovCode　AND LOV5.AttrTypeCode  = 'ZAT01060' AND LOV5.LanguageID =  #{LanguageID}
   	 		LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV6 ON LOV6.LovCode = TIA7.LovCode AND LOV6.AttrTypeCode  = 'ZAT01050' AND LOV6.LanguageID =  #{LanguageID} 
    		LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV7 ON LOV7.LovCode = TIA8.LovCode AND LOV7.AttrTypeCode  = 'ZAT01051' AND LOV7.LanguageID =  #{LanguageID}
    		LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV LOV8 ON LOV8.LovCode = TIA9.LovCode AND LOV8.AttrTypeCode  = 'AT00040' AND LOV8.LanguageID =  #{LanguageID}
		    LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TI.CurChangeSet = TCS.ChangeSetID
		    LEFT OUTER JOIN XBOLTADM.TB_ITEM ST ON TI.ItemID = ST.ToItemID AND ST.CategoryCode = 'ST1'
		    LEFT OUTER JOIN XBOLTADM.TW_ITEM_PATH_TXT TIPT ON TIPT.ItemID = TI.ItemID AND TIPT.LanguageID = #{LanguageID}
			LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TCD ON TCS.Status = TCD.TypeCode AND TCD.LanguageID = #{LanguageID} AND TCD.Category = 'CNGSTS'
		    LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSN ON TI.ItemID = TCSN.ItemID AND TCSN.ChangeType = 'NEW'
		    LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSM ON TI.ItemID = TCSM.ItemID AND TCSM.ChangeType = 'MOD' AND TI.ReleaseNo = TCSM.ChangeSetID
		 
		    WHERE (TI.Deleted != 1 )
		    AND TI.ClassCode = #{ClassCode}
				 
				 
				 	
				 		AND  EXISTS (
				 		SELECT 1
					    FROM XBOLTADM.TB_ITEM_DIM
					    WHERE ItemID = TI.ItemID
					      AND DimTypeID = '100001'
					      AND DimValueID IN ('SKO1'
					      
					      ,${siteCode}
					      
					      )
						)
				 	
				 	
				 		AND EXISTS (
							SELECT 1
					        FROM XBOLTADM.TB_ITEM_DIM
					        WHERE ItemID = TI.ItemID AND DimTypeID = '100001' AND DimValueID in (${siteCode})
						)
				 	
				 
			  	 
	 				And TCS.Status = #{csStatus}
	 			 
				
				    AND ISNULL(TCSN.ApproveDate, TI.CreationTime) BETWEEN #{SC_STR_DT1} AND #{SC_END_DT1}
					
				
					AND TCSM.ApproveDate BETWEEN #{SC_STR_DT2} AND #{SC_END_DT2}
				
				
	 		And (TI.Identifier like N'%'+#{searchValue}+'%' OR TIA.PlainText like N'%'+#{searchValue}+'%')
	 	
	 	 
		   AND (
		        TIA.PlainText like N'%'+#{totalInfo}+'%'
		        OR TIA10.PlainText like N'%'+#{totalInfo}+'%'
		        OR TIAF.PlainText like N'%'+#{totalInfo}+'%'
		    )
		 
		
	 		And TI.Identifier like N'%'+#{identifier}+'%'
	 	
	 	
	 		And TIA.PlainText like N'%'+#{itemName}+'%'
	 	
	 	
	 		And TI.Status = #{status}
	 	
	 	
	 		And ( TM.NameEN like N'%'+#{authorName}+'%' OR TM.Name like N'%'+#{authorName}+'%' )
	 		 	
	 	
	 		And TIA4.LovCode = #{ZAT01030}
	 	
		
	 		And TIA6.LovCode = #{ZAT01060}
	 	
	 	
	 		And TIA5.LovCode = #{ZAT01040}
	 	
	 	
	 		And TIA3.LovCode = #{ZAT01020}
	 	
	 	
	 		And TIA7.LovCode = #{ZAT01050}
	 	
	 	
	 		And TIA8.LovCode IN (
	 			
				 	#{item}
				
	 		)
	 	
	 	
	 		And TIA11.PlainText like N'%'+#{ZAT09005}+'%'
	 	
	 	
	 		And TIA12.PlainText like N'%'+#{ZAT09006}+'%'
	 	
	 	
	 		And TIA13.PlainText like N'%'+#{ZAT09007}+'%'
	 	
	   	
   		    AND TIA9.LovCode = #{AT00040}
		
		 
	 		And TIAF.PlainText like N'%'+#{processInfo}+'%'
	 	
		 
	 		And TIA10.PlainText like N'%'+#{keyWord}+'%'
	 	 
		
	 		And TOT.Name like N'%'+#{ownerTeamName}+'%'

SELECT Row_Number()OVER(ORDER BY TI.ClassCode ASC, TOT.Name ,TIA.PlainText ASC ) as RNUM , TI.ItemID AS s_itemID , TI.ItemID AS ItemID , TI.ClassCode , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , ISNULL(TIT.Icon, 'img_job.png') Icon , TIT.ItemTypeCode, TIF.ItemID, TIF.CategoryCode, ISNULL(TIS.SCOUNT, 0) AS SCOUNT , TIFA.PlainText as ParentName , TIFA.ItemID as ParentID , TIA.PlainText as ItemName
, TI.ItemID AS id , TI.ClassCode AS parent , ISNULL(TI.Identifier,'') + ' ' + ISNULL(TIA.PlainText,'') AS TreeName
, TD.Name as ClassName, TTD.Name as TypeName, ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End AS Name , TM.MemberID AS AuthorID, Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated, TI.Version, TI.Identifier , TIFA2.PlainText as ProcessInfo , ISNULL(TIFA3.PlainText, '') AS DocLev ,ISNULL(ATLOV1.Value, TIFA3.PlainText) AS DocLevValue
, ISNULL(TIPT.Path, '') AS ItemPath , ISNULL(TIPT.Path, '') AS path , 0 AS CHK , TSD.Name AS StatusName , TI.Status AS Status , CXN.ItemID AS CXNItemID , CXN.ItemTypeCode AS CXNItemTypeCode , CXN.ClassCode AS CXNClassCode , CXNCLS.Name AS CXNClassName , CXNCLS.Name AS LinkType , TI.OwnerTeamID , ( SELECT Count(*) FROM XBOLTADM.TB_ITEM WHERE ItemID in (Select Distinct ItemID From XBOLTADM.TB_ITEM WHERE ItemID in (Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1')
OR ItemID in (Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1')
) And ClassCode = TI.ClassCode ) AS ClassCNT , TTT.Name AS AuthorTeamName FROM XBOLTADM.TB_ITEM TI Left outer join ( SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT FROM XBOLTADM.TB_ITEM WHERE Deleted != '1' GROUP BY FromItemID ) TIS on TIS.FromItemID = TI.ItemID Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID AND TIF.CategoryCode = 'ST1' Left Outer JOIN XBOLTADM.TB_ITEM_CLASS TIT ON TI.ClassCode = TIT.ItemClassCode Left Outer Join XBOLTADM.TB_ITEM_ATTR TIFA on TIF.FromItemID = TIFA.ItemID AND TIFA.AttrTypeCode = 'AT00001' AND TIFA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TTD on TI.ItemTypeCode = TTD.TypeCode AND TTD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIFA2 on TI.ItemID = TIFA2.ItemID AND TIFA2.AttrTypeCode = 'AT00003' AND TIFA2.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIFA3 on TI.ItemID = TIFA3.ItemID AND TIFA3.AttrTypeCode = 'ZAT01020' AND TIFA3.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ATTR_TYPE_LOV ATLOV1 on ATLOV1.LovCode = TIFA3.LovCode and ATLOV1.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM CXN ON (CXN.FromItemID = TI.ItemID OR CXN.ToItemID = TI.ItemID) And (CXN.FromItemID = #{s_itemID} OR CXN.ToItemID = #{s_itemID}) And CXN.Deleted != 1 And CXN.CategoryCode = 'CN' Left outer join XBOLTADM.TB_DICTIONARY CXNCLS on CXN.ClassCode = CXNCLS.TypeCode AND CXNCLS.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TTT on TM.TeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TW_ITEM_PATH_TXT TIPT ON TIPT.ItemID = TI.ItemID And TIPT.LanguageID = #{languageID} WHERE TI.ItemID in ( Select Distinct TI.ItemID From XBOLTADM.TB_ITEM TI WHERE TI.ItemID in ( Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1' )
OR TI.ItemID in ( Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1' )
)
AND TI.ClassCode = #{ClassCode}
AND TI.ItemTypeCode = #{ItemTypeCode}
AND TI.CompanyID = #{CompanyCode}
AND ItemTypeCode IN
${item}
AND TI.ClassCode IN
${item}
AND TI.CategoryCode != 'TOJ'
And CXN.ItemTypeCode IN (${cxnTypeList})
And CXN.ClassCode NOT IN (${notInCxnClsList})
And TIFA3.PlainText = #{DocLev}
order by TI.ClassCode ASC, TOT.Name ASC, CXNClassCode, TI.Identifier ASC, TIA.PlainText ASC

SELECT A.MemberID as USER_ID /*사용자ID*/ ,A.Name as USER_NM /*사용자명*/ ,A.LoginId as LOGIN_ID /*로그인ID*/ ,A.MemberID as AUTH_ID /* 권한 */ ,A.CompanyID as COMPANY_ID /*업체ID*/ ,A.CompanyID as SEL_CMPNY_ID /*업체ID*/ ,B.Name as COMPANY_NM /*업체명*/ ,ISNULL(A.TeamID, 0) as TEAM_ID /*상위업체ID*/ ,ISNULL(A.EmployeeNum, 0) as EMPLOYEE_NM /*사원번호*/ ,A.Authority as AUTH_LEV /*권한레벨*/ ,ISNULL(D.Name, '') as TEAM_NAME ,ISNULL(UE.LanguageID,#{LANGUAGE}) AS CURR_LANG_TYPE ,ISNULL(UE.Name,ISNULL(E.Name, #{LANGUAGE})) AS CURR_LANG_NM ,ISNULL(UE.LanguageCode,ISNULL(E.LanguageCode, #{LANGUAGE})) AS CURR_LANG_CODE /*LanguageCode*/ ,A.ClientID AS CLIENT_ID ,A.MLVL, ISNULL(E.FontFamily, 'Malgun Gothic') AS DEF_FONT ,ISNULL(E.FontSize,14) AS DEF_FONT_SIZE ,ISNULL(E.FontStyle,'1') AS DEF_FONT_STYLE ,ISNULL(E.FontColor,'black') AS DEF_FONT_COLOR ,ISNULL(A.Email,'') AS EMAIL ,ISNULL(A.DefLanguageID,(Select LanguageID From XBOLTADM.TB_LANGUAGE Where IsDefault = 1042)) As DEF_LANGUAGE_ID /*Defult LanguageID*/ ,A.State AS STATE FROM XBOLTADM.TB_MEMBER A Left Outer Join XBOLTADM.TB_TEAM_TXT B on A.CompanyID = B.TeamID AND B.LanguageID = #{LANGUAGE} Left Outer Join XBOLTADM.TB_TEAM_TXT D on A.TeamID = D.TeamID AND D.LanguageID = #{LANGUAGE} LEFT OUTER JOIN XBOLTADM.TB_LANGUAGE UE ON UE.LanguageID = A.DefLanguageID LEFT OUTER JOIN XBOLTADM.TB_LANGUAGE E ON E.LanguageID = #{LANGUAGE} WHERE LoginId = #{LOGIN_ID}
AND Password = #{PASSWORD}
AND Active = #{active}
AND A.CompanyID = #{companyID}
AND A.ClientID = #{clientID}

		SELECT LovCode
  		FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE 1 =1 
  			
  				
  					AND AttrTypeCode = #{attrTypeCode}
				
				
  					AND AttrTypeCode LIKE 'ZAT%'
				
			
  			AND Value = #{value}
  			AND LanguageID = #{languageID}

		SELECT Value
  		FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE 1 =1 				
  			AND AttrTypeCode LIKE 'ZAT%'
  			AND LovCode = #{lovCode}
  			AND LanguageID = #{languageID}

		SELECT LovCode as lovCode
  		FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE  AttrTypeCode = #{lv3AttrTypeCode}
   			AND Value = #{docProc}

SELECT
	L3.ItemID
FROM XBOLTADM.TB_ITEM_ATTR L3
LEFT JOIN XBOLTADM.TB_ITEM L2ST ON 
	L2ST.CategoryCode = #{categoryCode}  
	AND L2ST.ToItemID = L3.ItemID
LEFT JOIN XBOLTADM.TB_ITEM_ATTR L2 ON 
	L2.AttrTypeCode = #{attrTypeCode}
	AND L2.ClassCode = #{lv2ClassCode}
	AND L2.LanguageID = #{languageId}
	AND L2.PlainText = #{docTyp}
	AND L2.ItemID = L2ST.FromItemID
LEFT JOIN XBOLTADM.TB_ITEM L1ST ON 
	L2ST.CategoryCode = #{categoryCode} 
	AND L1ST.ToItemID = L2.ItemID
LEFT JOIN XBOLTADM.TB_ITEM_ATTR L1 ON 
	L1.AttrTypeCode = #{attrTypeCode}
	AND L1.ClassCode = #{lv1ClassCode}
	AND L1.LanguageID = #{languageId}
	AND L1.PlainText = #{docArea}
	AND L1.ItemID = L1ST.FromItemID
WHERE L3.AttrTypeCode = #{attrTypeCode}
	AND L3.ClassCode = #{lv3ClassCode}
	AND L3.LanguageID = #{languageId}
	AND L3.PlainText = #{docProc}
	AND L2.ItemID IS NOT NULL 
	AND L1.ItemID IS NOT NULL

