SELECT ROW_NUMBER() OVER(ORDER BY TI.Identifier, TI.ClassCode) AS RNUM, TI.ItemID, ISNULL(TIA1.PlainText,'') AS ItemName, ISNULL(TIA3.PlainText,'') AS ManageTeamName, TI.ItemID AS id, TD.Name AS ClassName, TI.ClassCode, TIH.L0ItemID, TIH.L1ItemID, TIH.L2ItemID, TIH.L3ItemID, TI.Identifier, TITO.SortNum, TITO.CategoryCode, ISNULL(TMT.Name, '') AS TeamName, ISNULL(TOT.Name,'') AS OwnerTeamName, ISNULL(TM.Name,'') + CASE WHEN ISNULL(TM.NameEN,'') != '' THEN '(' + ISNULL(TM.NameEN,'') + ')' ELSE '' END AS Name, TCS.Version AS RevNo, CONVERT(nvarchar(10), TCSM.ApproveDate, 120) AS LastUpdated, ISNULL(CONVERT(nvarchar(10), TCSN.ApproveDate, 120),CONVERT(nvarchar(10), TI.CreationTime,120)) AS CreationTime FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM TITO ON TITO.ToITemID = TI.ItemID AND TITO.CategoryCode = 'ST1' AND TITO.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD ON TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 ON TI.ItemID = TIA1.ItemID AND TIA1.AttrTypeCode = 'AT00001' AND TIA1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TIC ON TIC.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT ON TMT.LanguageID = #{languageID} AND TMT.TeamID = TI.CompanyID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TOT.LanguageID = #{languageID} AND TOT.TeamID = TI.OwnerTeamID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 ON TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'ZAT04002' AND TIA3.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TW_ITEM_HIER TIH ON TI.ItemID = TIH.ItemID LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TI.CurChangeSet = TCS.ChangeSetID LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSN ON TI.ItemID = TCSN.ItemID AND TCSN.ChangeType = 'NEW' LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCSM ON TI.ItemID = TCSM.ItemID AND TCSM.ChangeType = 'MOD' AND TI.ReleaseNo = TCSM.ChangeSetID WHERE (TI.Deleted != 1 or (TI.Deleted = 1 AND TI.Status = 'REL') ) AND TI.ClassCode IN (#{defClassList})
AND TIH.L0ItemID = #{s_itemID}
AND TIH.L1ItemID = #{s_itemID}
AND TIH.L2ItemID = #{s_itemID}
AND TIH.L3ItemID = #{s_itemID}
AND NOT EXISTS ( SELECT 1 FROM XBOLTADM.TB_ITEM_DIM TID WHERE TID.ItemID = TI.ItemID AND TID.DimValueID NOT IN ( SELECT DimValueID FROM XBOLTADM.TB_ITEM_DIM WHERE ItemID = #{s_itemID} ) )
AND TIA1.PlainText like N'%'+#{searchValue}+'%'
AND TI.Identifier like N'%'+#{searchValue}+'%'
ORDER BY TI.ClassCode, TI.Identifier
